  phrases: [{ hi: "मुझे पानी चाहिए।", en: "I need water.", ipa: "mʊ-dʒʰeː paː-niː tʃaː-hi-eː" }, { hi: "एक चाय दीजिए।", en: "Please give one tea.", ipa: "eːk tʃaːj diː-dʒi-eː" }, { hi: "मुझे रोटी चाहिए।", en: "I need roti.", ipa: "mʊ-dʒʰeː roː-ʈiː tʃaː-hi-eː" }, { hi: "क्या पानी साफ़ है?", en: "Is the water clean?", ipa: "kjaː paː-niː saːf hɛː" }, { hi: "मुझे मसाला कम चाहिए।", en: "I want less spice.", ipa: "mʊ-dʒʰeː mə-saː-laː kəm tʃaː-hi-eː" }, { hi: "खाना अच्छा है।", en: "The food is good.", ipa: "kʰaː-naː ə-tʃːaː hɛː" }],
  grammar: "दीजिए means “please give,” and it is very common when ordering. You can say एक चाय दीजिए or पानी दीजिए. It is polite enough for most cafés and restaurants.",
  practice: ["Order one tea.", "Ask for water.", "Say you want less spice.", "Compliment the food.", "Ask if the water is clean."]
