  phrases: [{ hi: "मेन्यू दीजिए।", en: "Please give the menu.", ipa: "meː-njuː diː-dʒi-eː" }, { hi: "आप क्या सलाह देंगे?", en: "What do you recommend?", ipa: "aːp kjaː sə-laːh deːŋ-geː" }, { hi: "यह बहुत मसालेदार है?", en: "Is this very spicy?", ipa: "jəh bə-hʊt mə-saː-leː-daːr hɛː" }, { hi: "मुझे थाली चाहिए।", en: "I want a thali.", ipa: "mʊ-dʒʰeː tʰaː-liː tʃaː-hi-eː" }, { hi: "बिल दीजिए।", en: "Please give the bill.", ipa: "bɪl diː-dʒi-eː" }, { hi: "पानी ठंडा है।", en: "The water is cold.", ipa: "paː-niː ʈʰən-ɖaː hɛː" }],
