  phrases: [{ hi: "मैं शाकाहारी हूँ।", en: "I am vegetarian.", ipa: "mɛːn ʃaː-kaː-haː-riː huːn" }, { hi: "मुझे मांस नहीं चाहिए।", en: "I do not want meat.", ipa: "mʊ-dʒʰeː maːns nə-hiːn tʃaː-hi-eː" }, { hi: "क्या इसमें अंडा है?", en: "Does this have egg in it?", ipa: "kjaː ɪs-meːn əɳ-ɖaː hɛː" }, { hi: "बिना घी के, कृपया।", en: "Without ghee, please.", ipa: "bɪ-naː gʱiː keː krɪ-pə-jaː" }, { hi: "मुझे मूंगफली से एलर्जी है।", en: "I am allergic to peanuts.", ipa: "mʊ-dʒʰeː muːŋg-fə-liː seː eː-lər-dʒiː hɛː" }, { hi: "मसाला कम रखिए।", en: "Please keep the spice low.", ipa: "mə-saː-laː kəm rəkʰ-i-eː" }],
