  phrases: [{ hi: "वाई-फाई पासवर्ड क्या है?", en: "What is the Wi-Fi password?", ipa: "ʋaː-iː-faː-iː paːs-ʋərɖ kjaː hɛː" }, { hi: "मुझे सिम कार्ड चाहिए।", en: "I need a SIM card.", ipa: "mʊ-dʒʰeː sɪm kaːrɖ tʃaː-hi-eː" }, { hi: "मेरा फ़ोन चार्ज नहीं है।", en: "My phone is not charged.", ipa: "meː-raː foːn tʃaːrdʒ nə-hiːn hɛː" }, { hi: "चार्जर है?", en: "Do you have a charger?", ipa: "tʃaːr-dʒər hɛː" }, { hi: "नेटवर्क नहीं आ रहा है।", en: "The network is not working.", ipa: "neːʈ-ʋərk nə-hiːn aː rə-haː hɛː" }, { hi: "क्या मैं कॉल कर सकता हूँ?", en: "Can I make a call?", ipa: "kjaː mɛːn kɔːl kər sək-taː huːn" }],
