  phrases: [{ hi: "क्या यह मेज़ खाली है?", en: "Is this table available?", ipa: "kjaː jəh meːz kʰaː-liː hɛː" }, { hi: "मुझे बिना चीनी की चाय चाहिए।", en: "I want tea without sugar.", ipa: "mʊ-dʒʰeː bɪ-naː tʃiː-niː kiː tʃaːj tʃaː-hi-eː" }, { hi: "एक कॉफ़ी दीजिए।", en: "Please give one coffee.", ipa: "eːk kɔː-fiː diː-dʒi-eː" }, { hi: "कुछ नाश्ता है?", en: "Do you have any snacks?", ipa: "kʊtʃʰ naːʃ-taː hɛː" }, { hi: "यह गरम है?", en: "Is this hot?", ipa: "jəh gərm hɛː" }, { hi: "मैं यहाँ बैठ सकता हूँ?", en: "Can I sit here?", ipa: "mɛːn jə-haːn bɛːʈʰ sək-taː huːn" }],
