  phrases: [{ hi: "क्या आप कार्ड लेते हैं?", en: "Do you take card?", ipa: "kjaː aːp kaːrɖ leː-teː hɛːn" }, { hi: "मैं नकद दूँगा।", en: "I will pay cash.", ipa: "mɛːn nə-kəd duːŋ-gaː" }, { hi: "एटीएम कहाँ है?", en: "Where is the ATM?", ipa: "eː-ʈiː-em kə-haːn hɛː" }, { hi: "रसीद चाहिए।", en: "I need a receipt.", ipa: "rə-siːd tʃaː-hi-eː" }, { hi: "चेंज है?", en: "Do you have change?", ipa: "tʃeːndʒ hɛː" }, { hi: "भुगतान हो गया।", en: "The payment is done.", ipa: "bʱʊg-taːn hoː gə-jaː" }],
