  phrases: [{ hi: "मुझे यह पसंद है।", en: "I like this.", ipa: "mʊ-dʒʰeː jəh pə-sənd hɛː" }, { hi: "मुझे यह पसंद नहीं है।", en: "I do not like this.", ipa: "mʊ-dʒʰeː jəh pə-sənd nə-hiːn hɛː" }, { hi: "मुझे स्थानीय खाना पसंद है।", en: "I like local food.", ipa: "mʊ-dʒʰeː stʰaː-niː-jə kʰaː-naː pə-sənd hɛː" }, { hi: "कौन सा बेहतर है?", en: "Which one is better?", ipa: "kɔːn saː beː-hə-tər hɛː" }, { hi: "मैं कुछ नया कोशिश करना चाहता हूँ।", en: "I want to try something new.", ipa: "mɛːn kʊtʃʰ nə-jaː koː-ʃɪʃ kər-naː tʃaːh-taː huːn" }, { hi: "यह सबसे अच्छा है।", en: "This is the best.", ipa: "jəh səb-seː ə-tʃːaː hɛː" }],
  grammar: "To say you like something, use मुझे ... पसंद है. To say you do not like it, place नहीं before है: मुझे यह पसंद नहीं है. This pattern is more natural than translating “I like” word-for-word.",
  practice: ["Say you like local food.", "Say you do not like something.", "Ask which one is better.", "Say you want to try something new.", "Say something is the best."]
