  phrases: [{ hi: "आज मेरी यात्रा अच्छी रही।", en: "My travel went well today.", ipa: "aːdʒ meː-riː jaː-traː ə-tʃːiː rə-hiː" }, { hi: "मुझे यहाँ अच्छा लगा।", en: "I liked it here.", ipa: "mʊ-dʒʰeː jə-haːn ə-tʃːaː lə-gaː" }, { hi: "क्या आप मेरी मदद कर सकते हैं?", en: "Can you help me?", ipa: "kjaː aːp meː-riː mə-dəd kər sək-teː hɛːn" }, { hi: "मुझे यह जगह सुरक्षित लगती है।", en: "This place feels safe to me.", ipa: "mʊ-dʒʰeː jəh dʒə-gəh sʊ-rək-ʂɪt ləg-tiː hɛː" }, { hi: "मैं दोबारा आना चाहूँगा।", en: "I would like to come again.", ipa: "mɛːn doː-baː-raː aː-naː tʃaː-huːŋ-gaː" }, { hi: "आपका बहुत धन्यवाद।", en: "Thank you very much.", ipa: "aːp-kaː bə-hʊt dʱən-jə-ʋaːd" }],
