var CONVERSATIONS_EN_HI = [
{ title: "Ordering at a Café", scene: "You are in a small café in Delhi after sightseeing. You want tea without sugar and a light snack.", lines: [{ who: "them", hi: "नमस्ते, आप क्या लेंगे?", en: "Hello, what will you have?" }, { who: "you", hi: "नमस्ते, मुझे एक चाय चाहिए।", en: "Hello, I would like one tea." }, { who: "them", hi: "चीनी डालें?", en: "Should I add sugar?" }, { who: "you", hi: "नहीं, बिना चीनी की चाय चाहिए।", en: "No, I want tea without sugar." }, { who: "them", hi: "ठीक है, और कुछ?", en: "Okay, anything else?" }, { who: "you", hi: "कुछ नाश्ता है?", en: "Do you have any snacks?" }, { who: "them", hi: "हाँ, समोसा और सैंडविच है।", en: "Yes, we have samosas and sandwiches." }, { who: "you", hi: "एक समोसा दीजिए।", en: "Please give one samosa." }, { who: "them", hi: "ज़रूर, बैठिए।", en: "Certainly, please sit." }, { who: "you", hi: "धन्यवाद, क्या यह मेज़ खाली है?", en: "Thank you, is this table available?" }, { who: "them", hi: "हाँ, यह खाली है।", en: "Yes, it is available." }, { who: "you", hi: "बहुत अच्छा, धन्यवाद।", en: "Very good, thank you." }] },
{ title: "Hotel Check-In", scene: "You arrive at a hotel in Jaipur. You have a booking and need the Wi-Fi password.", lines: [{ who: "them", hi: "नमस्ते, होटल में आपका स्वागत है।", en: "Hello, welcome to the hotel." }, { who: "you", hi: "नमस्ते, मेरी बुकिंग है।", en: "Hello, I have a booking." }, { who: "them", hi: "आपका नाम क्या है?", en: "What is your name?" }, { who: "you", hi: "मेरा नाम जॉन स्मिथ है।", en: "My name is John Smith." }, { who: "them", hi: "पासपोर्ट दीजिए, कृपया।", en: "Please give your passport." }, { who: "you", hi: "यह मेरा पासपोर्ट है।", en: "This is my passport." }, { who: "them", hi: "आपका कमरा तीसरी मंज़िल पर है।", en: "Your room is on the third floor." }, { who: "you", hi: "धन्यवाद, वाई-फाई पासवर्ड क्या है?", en: "Thank you, what is the Wi-Fi password?" }, { who: "them", hi: "पासवर्ड “Jaipur2026” है।", en: "The password is “Jaipur2026.”" }, { who: "you", hi: "क्या मुझे एक तौलिया मिल सकता है?", en: "Can I get one towel?" }, { who: "them", hi: "हाँ, हम अभी भेजते हैं।", en: "Yes, we will send it now." }, { who: "you", hi: "आपका बहुत धन्यवाद।", en: "Thank you very much." }] },
{ title: "Asking for Directions", scene: "You are near Connaught Place in Delhi and need to find the metro station. You stop a local person and ask politely.", lines: [{ who: "you", hi: "माफ़ कीजिए, मेट्रो स्टेशन कहाँ है?", en: "Excuse me, where is the metro station?" }, { who: "them", hi: "मेट्रो स्टेशन पास में है।", en: "The metro station is nearby." }, { who: "you", hi: "मुझे कैसे जाना है?", en: "How do I need to go?" }, { who: "them", hi: "सीधे जाइए, फिर बाएँ मुड़िए।", en: "Go straight, then turn left." }, { who: "you", hi: "कितनी दूर है?", en: "How far is it?" }, { who: "them", hi: "पाँच मिनट पैदल है।", en: "It is five minutes on foot." }, { who: "you", hi: "क्या आप नक्शे पर दिखा सकते हैं?", en: "Can you show me on the map?" }, { who: "them", hi: "हाँ, यहाँ देखिए।", en: "Yes, look here." }, { who: "you", hi: "धन्यवाद, यह बहुत मददगार है।", en: "Thank you, this is very helpful." }, { who: "them", hi: "कोई बात नहीं।", en: "No problem." }, { who: "you", hi: "आपका दिन अच्छा हो।", en: "Have a good day." }, { who: "them", hi: "धन्यवाद, आपका भी।", en: "Thank you, yours too." }] },
{ title: "At a Restaurant", scene: "You are eating dinner in Lucknow. You want a vegetarian dish, less spice, and the bill at the end.", lines: [{ who: "them", hi: "नमस्ते, मेन्यू लीजिए।", en: "Hello, please take the menu." }, { who: "you", hi: "धन्यवाद, क्या शाकाहारी खाना है?", en: "Thank you, is there vegetarian food?" }, { who: "them", hi: "हाँ, दाल, सब्ज़ी, और थाली है।", en: "Yes, there are lentils, vegetables, and thali." }, { who: "you", hi: "आप क्या सलाह देंगे?", en: "What do you recommend?" }, { who: "them", hi: "शाकाहारी थाली अच्छी है।", en: "The vegetarian thali is good." }, { who: "you", hi: "ठीक है, एक शाकाहारी थाली दीजिए।", en: "Okay, please give one vegetarian thali." }, { who: "them", hi: "मसाला ठीक है?", en: "Is the spice level okay?" }, { who: "you", hi: "मसाला कम रखिए, कृपया।", en: "Please keep the spice low." }, { who: "them", hi: "ज़रूर।", en: "Certainly." }, { who: "you", hi: "और पानी भी दीजिए।", en: "And please give water too." }, { who: "them", hi: "ठीक है।", en: "Okay." }, { who: "you", hi: "खाने के बाद बिल दीजिए।", en: "Please give the bill after the food." }] },
{ title: "Buying Train Tickets", scene: "You are at a railway station in Varanasi. You need two tickets and want to know the platform.", lines: [{ who: "them", hi: "नमस्ते, कहाँ जाना है?", en: "Hello, where do you need to go?" }, { who: "you", hi: "मुझे प्रयागराज जाना है।", en: "I need to go to Prayagraj." }, { who: "them", hi: "कितने टिकट चाहिए?", en: "How many tickets do you need?" }, { who: "you", hi: "दो टिकट चाहिए।", en: "I need two tickets." }, { who: "them", hi: "आज की ट्रेन चाहिए?", en: "Do you need today’s train?" }, { who: "you", hi: "हाँ, आज शाम की ट्रेन चाहिए।", en: "Yes, I need the evening train today." }, { who: "them", hi: "ट्रेन सात बजे है।", en: "The train is at seven o’clock." }, { who: "you", hi: "कौन सा प्लेटफ़ॉर्म?", en: "Which platform?" }, { who: "them", hi: "प्लेटफ़ॉर्म नंबर तीन।", en: "Platform number three." }, { who: "you", hi: "ट्रेन में देरी है?", en: "Is the train delayed?" }, { who: "them", hi: "नहीं, ट्रेन समय पर है।", en: "No, the train is on time." }, { who: "you", hi: "धन्यवाद।", en: "Thank you." }] },
{ title: "Shopping in a Market", scene: "You are shopping for a scarf in Jaipur’s old city. You want to ask the price and bargain politely.", lines: [{ who: "them", hi: "आइए, क्या चाहिए?", en: "Come in, what do you need?" }, { who: "you", hi: "मुझे यह कपड़ा पसंद है।", en: "I like this cloth." }, { who: "them", hi: "यह बहुत अच्छा है।", en: "This is very good." }, { who: "you", hi: "यह कितने का है?", en: "How much is this?" }, { who: "them", hi: "यह आठ सौ रुपये का है।", en: "This is eight hundred rupees." }, { who: "you", hi: "यह बहुत महँगा है।", en: "This is very expensive." }, { who: "them", hi: "अच्छा, सात सौ दे दीजिए।", en: "Okay, give seven hundred." }, { who: "you", hi: "कुछ छूट मिलेगी?", en: "Will I get some discount?" }, { who: "them", hi: "आख़िरी दाम छह सौ है।", en: "The final price is six hundred." }, { who: "you", hi: "ठीक है, मैं यह लूँगा।", en: "Okay, I will take this." }, { who: "them", hi: "नकद या कार्ड?", en: "Cash or card?" }, { who: "you", hi: "मैं नकद दूँगा, रसीद दीजिए।", en: "I will pay cash, please give a receipt." }] },
{ title: "At the Pharmacy", scene: "You are in Delhi and have a headache after a long day of travel. You go to a pharmacy and ask for basic help.", lines: [{ who: "them", hi: "नमस्ते, क्या चाहिए?", en: "Hello, what do you need?" }, { who: "you", hi: "नमस्ते, मुझे सिरदर्द है।", en: "Hello, I have a headache." }, { who: "them", hi: "बुखार भी है?", en: "Do you also have a fever?" }, { who: "you", hi: "नहीं, बुखार नहीं है।", en: "No, I do not have a fever." }, { who: "them", hi: "आपको यह दवा लेनी चाहिए।", en: "You should take this medicine." }, { who: "you", hi: "क्या मुझे पर्ची चाहिए?", en: "Do I need a prescription?" }, { who: "them", hi: "नहीं, इसके लिए पर्ची नहीं चाहिए।", en: "No, you do not need a prescription for this." }, { who: "you", hi: "इसे कैसे लेना है?", en: "How should I take it?" }, { who: "them", hi: "खाना खाने के बाद लीजिए।", en: "Take it after eating food." }, { who: "you", hi: "ठीक है, कितने रुपये?", en: "Okay, how many rupees?" }, { who: "them", hi: "पचास रुपये।", en: "Fifty rupees." }, { who: "you", hi: "धन्यवाद।", en: "Thank you." }] },
{ title: "Small Talk with a Local", scene: "You are sitting near the ghats in Varanasi and start a friendly conversation with a local person. You talk about the city and your visit.", lines: [{ who: "you", hi: "नमस्ते, क्या आप यहीं रहते हैं?", en: "Hello, do you live here?" }, { who: "them", hi: "हाँ, मैं यहीं रहता हूँ।", en: "Yes, I live here." }, { who: "you", hi: "यह शहर बहुत सुंदर है।", en: "This city is very beautiful." }, { who: "them", hi: "धन्यवाद, क्या आप पहली बार आए हैं?", en: "Thank you, have you come for the first time?" }, { who: "you", hi: "हाँ, मैं पहली बार भारत आया हूँ।", en: "Yes, I have come to India for the first time." }, { who: "them", hi: "आपको यहाँ कैसा लग रहा है?", en: "How are you finding it here?" }, { who: "you", hi: "मुझे यहाँ बहुत अच्छा लग रहा है।", en: "I am liking it here very much." }, { who: "them", hi: "क्या आपने स्थानीय खाना खाया?", en: "Have you eaten local food?" }, { who: "you", hi: "हाँ, मुझे स्थानीय खाना पसंद है।", en: "Yes, I like local food." }, { who: "them", hi: "बहुत अच्छा, फिर से आइए।", en: "Very good, come again." }, { who: "you", hi: "ज़रूर, मैं दोबारा आना चाहूँगा।", en: "Definitely, I would like to come again." }, { who: "them", hi: "आपकी यात्रा शुभ हो।", en: "Have a good journey." }] }
];
